<body>
    <div class="container">
        <h1>2048</h1>
        <div class="info">
            <div class="score-box">
                Score: <span id="score">0</span>
            </div>
            <button id="reset">New Game</button>
        </div>
        <div id="board"></div>
    </div>

    <script>
        class Game2048 {
            constructor() {
                this.size = 4;
                this.grid = Array(this.size).fill(null).map(() => Array(this.size).fill(0));
                this.currentScore = 0;
            }

            reset() {
                this.grid = Array(this.size).fill(null).map(() => Array(this.size).fill(0));
                this.currentScore = 0;
                this.addNewTile();
                this.addNewTile();
                this.render();
            }

            board() {
                return this.grid.map(row => [...row]);
            }

            setBoard(arr) {
                this.grid = arr.map(row => [...row]);
                this.render();
            }

            score() {
                return this.currentScore;
            }

            addNewTile() {
                const empty = [];
                for (let i = 0; i < this.size; i++) {
                    for (let j = 0; j < this.size; j++) {
                        if (this.grid[i][j] === 0) {
                            empty.push([i, j]);
                        }
                    }
                }

                if (empty.length === 0) return;

                const [row, col] = empty[Math.floor(Math.random() * empty.length)];
                const value = Math.random() < 0.9 ? 2 : 4;
                this.grid[row][col] = value;
            }

            move(direction) {
                const oldGrid = this.grid.map(row => [...row]);

                if (direction === 'left') {
                    this.moveLeft();
                } else if (direction === 'right') {
                    this.moveRight();
                } else if (direction === 'up') {
                    this.moveUp();
                } else if (direction === 'down') {
                    this.moveDown();
                }

                const changed = !this.gridEqual(oldGrid, this.grid);

                if (changed) {
                    this.addNewTile();
                    this.render();
                }

                return changed;
            }

            gridEqual(a, b) {
                for (let i = 0; i < this.size; i++) {
                    for (let j = 0; j < this.size; j++) {
                        if (a[i][j] !== b[i][j]) return false;
                    }
                }
                return true;
            }

            moveLeft() {
                for (let i = 0; i < this.size; i++) {
                    this.grid[i] = this.slideMerge(this.grid[i]);
                }
            }

            moveRight() {
                for (let i = 0; i < this.size; i++) {
                    this.grid[i] = this.slideMerge(this.grid[i].reverse()).reverse();
                }
            }

            moveUp() {
                for (let j = 0; j < this.size; j++) {
                    const column = [];
                    for (let i = 0; i < this.size; i++) {
                        column.push(this.grid[i][j]);
                    }
                    const merged = this.slideMerge(column);
                    for (let i = 0; i < this.size; i++) {
                        this.grid[i][j] = merged[i];
                    }
                }
            }

            moveDown() {
                for (let j = 0; j < this.size; j++) {
                    const column = [];
                    for (let i = 0; i < this.size; i++) {
                        column.push(this.grid[i][j]);
                    }
                    const merged = this.slideMerge(column.reverse()).reverse();
                    for (let i = 0; i < this.size; i++) {
                        this.grid[i][j] = merged[i];
                    }
                }
            }

            slideMerge(line) {
                const nonZero = line.filter(x => x !== 0);
                const merged = [];
                const mergedIndices = new Set();

                for (let i = 0; i < nonZero.length; i++) {
                    if (mergedIndices.has(i)) continue;

                    if (i + 1 < nonZero.length && nonZero[i] === nonZero[i + 1]) {
                        const newValue = nonZero[i] * 2;
                        merged.push(newValue);
                        this.currentScore += newValue;
                        mergedIndices.add(i + 1);
                        i++;
                    } else {
                        merged.push(nonZero[i]);
                    }
                }

                while (merged.length < this.size) {
                    merged.push(0);
                }

                return merged;
            }

            render() {
                const boardEl = document.getElementById('board');
                boardEl.innerHTML = '';

                for (let i = 0; i < this.size; i++) {
                    for (let j = 0; j < this.size; j++) {
                        const tile = document.createElement('div');
                        tile.className = 'tile';
                        tile.setAttribute('data-value', this.grid[i][j]);
                        tile.textContent = this.grid[i][j] === 0 ? '' : this.grid[i][j];
                        boardEl.appendChild(tile);
                    }
                }

                document.getElementById('score').textContent = this.currentScore;
            }
        }

        const game = new Game2048();

        window.game = {
            size: game.size,
            reset: () => game.reset(),
            move: (direction) => game.move(direction),
            board: () => game.board(),
            setBoard: (arr) => game.setBoard(arr),
            score: () => game.score(),
        };

        document.getElementById('reset').addEventListener('click', () => {
            game.reset();
        });

        document.addEventListener('keydown', (e) => {
            if (e.key === 'ArrowLeft') {
                e.preventDefault();
                game.move('left');
            } else if (e.key === 'ArrowRight') {
                e.preventDefault();
                game.move('right');
            } else if (e.key === 'ArrowUp') {
                e.preventDefault();
                game.move('up');
            } else if (e.key === 'ArrowDown') {
                e.preventDefault();
                game.move('down');
            }
        });

        game.reset();
    </script>
</body>
